import heapq

class Solution:
    def minimumCost(self, target, words, costs):
        n = len(target)
        dist = [float('inf')] * (n + 1)
        dist[0] = 0
        pq = [(0, 0)]
        while pq:
            d, i = heapq.heappop(pq)
            if d > dist[i]:
                continue
            if i == n:
                continue
            for w, c in zip(words, costs):
                L = len(w)
                if i + L <= n and target[i:i + L] == w:
                    nd = d + c
                    if nd < dist[i + L]:
                        dist[i + L] = nd
                        heapq.heappush(pq, (nd, i + L))
        return dist[n] if dist[n] < float('inf') else -1

