        dp = [INF] * (n + 1)
        dp[0] = 0
        pairs = list(zip(words, costs))
        for i in range(n):
            if dp[i] == INF:
                continue
            for w, c in pairs:
                L = len(w)
                if i + L <= n and target[i:i + L] == w:
                    if dp[i] + c < dp[i + L]:
                        dp[i + L] = dp[i] + c
        return dp[n] if dp[n] < INF else -1

